public class Logical_operator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int num = 55;
			 
		     System.out.println(num >= 10 && num <= 10 || !(num==55));

		     
		     System.out.println(num >= 1 && num <= 100 || !(num==56));
		    	     
	
		}
}
